			jobs <- i
		}
		close(jobs) // workers drain and exit
	}()

	go func() {
		wg.Wait()
		close(results) // close results once all workers are done
	}()

	sum := 0
	for r := range results {
		sum += r
	}
	fmt.Println("sum of doubled:", sum) // 2*(1+2+3+4+5+6) = 42
