// Cache is a concurrency-safe string map. Reads take a shared RLock; writes take
// the exclusive Lock.
type Cache struct {
	mu sync.RWMutex
	m  map[string]string
}

func NewCache() *Cache { return &Cache{m: map[string]string{}} }

